SELECT 
FROM equipment e
LEFT JOIN dormitories d ON d.id = e.dormitory_id
LEFT JOIN rooms rm ON rm.id = e.room_id AND rm.deleted_at IS NULL
WHERE e.deleted_at IS NULL

    AND e.dormitory_id = #{dormitoryId}


    AND e.status = #{status}


    AND (e.name LIKE CONCAT('%', #{keyword}, '%') OR e.serial_number LIKE CONCAT('%', #{keyword}, '%'))

ORDER BY e.created_at DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(1)
FROM equipment e
WHERE e.deleted_at IS NULL

    AND e.dormitory_id = #{dormitoryId}


    AND e.status = #{status}


    AND (e.name LIKE CONCAT('%', #{keyword}, '%') OR e.serial_number LIKE CONCAT('%', #{keyword}, '%'))
